    static void ejercicio1(int n, char c1, char c2) {

        int contador = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (i == 0 || i == n - 1 || j == 0 || j == n - 1)
                    System.out.print((contador % 2 == 0 ? c1 : c2) + " ");
                else
                    System.out.print("  ");
                contador++;
            }
            System.out.println();
        }
    }

    static void ejercicio2Impar(int n, char c) {

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (i == n / 2 || j == n / 2)
                    System.out.print(c + " ");
                else
                    System.out.print("  ");
            }
            System.out.println();
        }
    }

    static void ejercicio2Par(int n, char c) {

        for (int i = 0; i <= n; i++) {
            for (int j = 0; j < n; j++) {
                if (i == n / 2)
                    System.out.print(c + " ");
                else if (j == n / 2)
                    System.out.print("\b" + c);
                else
                    System.out.print("  ");
            }
            System.out.println();
        }
    }

    static void ejercicio2(int n, char c) {

        if (n % 2 == 0)
            ejercicio2Par(n, c);
        else
            ejercicio2Impar(n, c);
    }

    static void ejercicio3(int base, int altura, char c) {

        for (int i = 0; i < altura; i++) {

            for (int j = 0; j < base + i; j++) {
                if (j >= i)
                    System.out.print(c);
                else
                    System.out.print(" ");
            }
            System.out.println();
        }
    }

