     * @param n El la altura del triángulo
     */
    static void triangulo(int n) {

        System.out.println();
        for (int i = 0; i < n; i++) {
            for (int j = 0; j <= i; j++) {
                System.out.print("* ");
            }
            System.out.println();
        }
        System.out.println();
    }

    /**
     * Dibuja un triángulo sin relleno formado por asteriscos
     * 
     * @param n Es la altura del triángulo
     */
    static void trianguloSinRelleno(int n) {

        System.out.println();
        for (int i = 0; i < n; i++) {
            for (int j = 0; j <= i; j++) {

                if (i == 0 || i == n - 1 || j == 0 || j == i)
                    System.out.print("* ");
                else
                    System.out.print("  ");
            }
            System.out.println();
        }
        System.out.println();
    }

}

