            for (int i = 1; i <= n; i++) {
                String nombreFichero = ruta + "/nombre(" + i + ").txt";
                try (BufferedWriter writer = new BufferedWriter(new FileWriter(nombreFichero))) {
                    writer.write("Este es el fichero nombre(" + i + ").txt");
