            }
            scn.close();
        } catch (IOException e) {
            System.out.println("Ocurrió un error al leer el archivo " + nombreArchivo);
        }
        System.out.println("La palabra '" + palabraBuscada + "' aparece " + contador + " veces en el archivo.");
